2	/// How to add a new function or property to the Bun global
3	///
4	/// - Add a callback or property to the below struct
5	/// - @export it in the appropriate place
6	/// - Update "@begin bunObjectTable" in BunObject.cpp
7	///     - Getters use a generated wrapper function `BunObject_getter_wrap_<name>`
8	/// - Update "BunObject+exports.h"
9	/// - Run `bun run build`
10	pub const BunObject = struct {
11	    // --- Callbacks ---
12	    pub const allocUnsafe = toJSCallback(Bun.allocUnsafe);
13	    pub const build = toJSCallback(Bun.JSBundler.buildFn);
14	    pub const color = toJSCallback(bun.css.CssColor.jsFunctionColor);
15	    pub const connect = toJSCallback(host_fn.wrapStaticMethod(api.Listener, "connect", false));
16	    pub const createParsedShellScript = toJSCallback(bun.shell.ParsedShellScript.createParsedShellScript);
17	    pub const createShellInterpreter = toJSCallback(bun.shell.Interpreter.createShellInterpreter);
18	    pub const deflateSync = toJSCallback(JSZlib.deflateSync);
19	    pub const file = toJSCallback(WebCore.Blob.constructBunFile);
20	    pub const gunzipSync = toJSCallback(JSZlib.gunzipSync);
21	    pub const gzipSync = toJSCallback(JSZlib.gzipSync);
22	    pub const indexOfLine = toJSCallback(Bun.indexOfLine);
23	    pub const inflateSync = toJSCallback(JSZlib.inflateSync);
