239	pub fn braces(global: *jsc.JSGlobalObject, brace_str: bun.String, opts: gen.BracesOptions) bun.JSError!jsc.JSValue {
240	    const brace_slice = brace_str.toUTF8(bun.default_allocator);
241	    defer brace_slice.deinit();
242	
243	    var arena = std.heap.ArenaAllocator.init(bun.default_allocator);
244	    defer arena.deinit();
245	
246	    var lexer_output = lexer_output: {
247	        if (bun.strings.isAllASCII(brace_slice.slice())) {
248	            break :lexer_output Braces.Lexer.tokenize(arena.allocator(), brace_slice.slice()) catch |err| {
249	                return global.throwError(err, "failed to tokenize braces");
250	            };
251	        }
252	
253	        break :lexer_output Braces.NewLexer(.wtf8).tokenize(arena.allocator(), brace_slice.slice()) catch |err| {
254	            return global.throwError(err, "failed to tokenize braces");
255	        };
256	    };
257	
258	    const expansion_count = Braces.calculateExpandedAmount(lexer_output.tokens.items[0..]);
259	
260	    if (opts.tokenize) {
261	        const str = bun.handleOom(std.fmt.allocPrint(global.bunVM().allocator, "{f}", .{std.json.fmt(lexer_output.tokens.items[0..], .{})}));
262	        defer global.bunVM().allocator.free(str);
263	        var bun_str = bun.String.fromBytes(str);
264	        return bun_str.toJS(global);
265	    }
266	    if (opts.parse) {
267	        var parser = Braces.Parser.init(lexer_output.tokens.items[0..], arena.allocator());
268	        const ast_node = parser.parse() catch |err| {
269	            return global.throwError(err, "failed to parse braces");
270	        };
271	        const str = bun.handleOom(std.fmt.allocPrint(global.bunVM().allocator, "{f}", .{std.json.fmt(ast_node, .{})}));
272	        defer global.bunVM().allocator.free(str);
273	        var bun_str = bun.String.fromBytes(str);
274	        return bun_str.toJS(global);
275	    }
276	
277	    if (expansion_count == 0) {
278	        return bun.String.toJSArray(global, &.{brace_str});
279	    }
280	
281	    var expanded_strings = try arena.allocator().alloc(std.array_list.Managed(u8), expansion_count);
282	
283	    for (0..expansion_count) |i| {
284	        expanded_strings[i] = std.array_list.Managed(u8).init(arena.allocator());
285	    }
286	
287	    Braces.expand(
288	        arena.allocator(),
289	        lexer_output.tokens.items[0..],
290	        expanded_strings,
291	        lexer_output.contains_nested,
292	    ) catch |err| switch (err) {
293	        error.OutOfMemory => |e| return e,
294	        error.UnexpectedToken => return global.throwPretty("Unexpected token while expanding braces", .{}),
295	    };
296	
297	    var out_strings = try arena.allocator().alloc(bun.String, expansion_count);
298	    for (0..expansion_count) |i| {
299	        out_strings[i] = bun.String.fromBytes(expanded_strings[i].items[0..]);
300	    }
301	
302	    return bun.String.toJSArray(global, out_strings[0..]);
303	}
