305	pub fn which(globalThis: *jsc.JSGlobalObject, callframe: *jsc.CallFrame) bun.JSError!jsc.JSValue {
306	    const arguments_ = callframe.arguments_old(2);
307	    const path_buf = bun.path_buffer_pool.get();
308	    defer bun.path_buffer_pool.put(path_buf);
309	    var arguments = jsc.CallFrame.ArgumentsSlice.init(globalThis.bunVM(), arguments_.slice());
310	    defer arguments.deinit();
311	    const path_arg = arguments.nextEat() orelse {
312	        return globalThis.throw("which: expected 1 argument, got 0", .{});
313	    };
314	
315	    var path_str: ZigString.Slice = ZigString.Slice.empty;
316	    var bin_str: ZigString.Slice = ZigString.Slice.empty;
317	    var cwd_str: ZigString.Slice = ZigString.Slice.empty;
318	    defer {
319	        path_str.deinit();
320	        bin_str.deinit();
321	        cwd_str.deinit();
322	    }
323	
324	    if (path_arg.isEmptyOrUndefinedOrNull()) {
325	        return jsc.JSValue.jsNull();
326	    }
327	
328	    bin_str = try path_arg.toSlice(globalThis, globalThis.bunVM().allocator);
329	    if (globalThis.hasException()) {
330	        return .zero;
331	    }
332	
333	    if (bin_str.len >= bun.MAX_PATH_BYTES) {
334	        return globalThis.throw("bin path is too long", .{});
335	    }
336	
337	    if (bin_str.len == 0) {
338	        return jsc.JSValue.jsNull();
339	    }
340	
341	    path_str = ZigString.Slice.fromUTF8NeverFree(
342	        globalThis.bunVM().transpiler.env.get("PATH") orelse "",
343	    );
344	    cwd_str = ZigString.Slice.fromUTF8NeverFree(
345	        globalThis.bunVM().transpiler.fs.top_level_dir,
346	    );
347	
348	    if (arguments.nextEat()) |arg| {
349	        if (!arg.isEmptyOrUndefinedOrNull() and arg.isObject()) {
350	            if (try arg.get(globalThis, "PATH")) |str_| {
351	                path_str = try str_.toSlice(globalThis, globalThis.bunVM().allocator);
352	            }
353	
354	            if (try arg.get(globalThis, "cwd")) |str_| {
355	                cwd_str = try str_.toSlice(globalThis, globalThis.bunVM().allocator);
356	            }
357	        }
358	    }
359	
360	    if (Which.which(
361	        path_buf,
362	        path_str.slice(),
363	        cwd_str.slice(),
364	        bin_str.slice(),
365	    )) |bin_path| {
366	        return ZigString.init(bin_path).withEncoding().toJS(globalThis);
367	    }
368	
369	    return jsc.JSValue.jsNull();
370	}
