372	pub fn inspectTable(globalThis: *jsc.JSGlobalObject, callframe: *jsc.CallFrame) bun.JSError!jsc.JSValue {
373	    var args_buf = callframe.argumentsUndef(5);
374	    var all_arguments = args_buf.mut();
375	    if (all_arguments[0].isUndefinedOrNull() or !all_arguments[0].isObject())
376	        return bun.String.empty.toJS(globalThis);
377	
378	    for (all_arguments) |arg| {
379	        arg.protect();
380	    }
381	    defer {
382	        for (all_arguments) |arg| {
383	            arg.unprotect();
384	        }
385	    }
386	
387	    var arguments = all_arguments[0..];
388	    const value = arguments[0];
389	
390	    if (!arguments[1].isArray()) {
391	        arguments[2] = arguments[1];
392	        arguments[1] = .js_undefined;
393	    }
394	
395	    var formatOptions = ConsoleObject.FormatOptions{
396	        .enable_colors = false,
397	        .add_newline = false,
398	        .flush = false,
399	        .max_depth = 5,
400	        .quote_strings = true,
401	        .ordered_properties = false,
402	        .single_line = true,
403	    };
404	    if (arguments[2].isObject()) {
405	        try formatOptions.fromJS(globalThis, arguments[2..]);
406	    }
407	
408	    // very stable memory address
409	    var array = std.Io.Writer.Allocating.init(bun.default_allocator);
410	    defer array.deinit();
411	    const writer = &array.writer;
412	
413	    const Writer = @TypeOf(writer);
414	    const properties: JSValue = if (arguments[1].jsType().isArray()) arguments[1] else .js_undefined;
415	    var table_printer = try ConsoleObject.TablePrinter.init(
416	        globalThis,
417	        .Log,
418	        value,
419	        properties,
420	    );
421	    table_printer.value_formatter.depth = formatOptions.max_depth;
422	    table_printer.value_formatter.ordered_properties = formatOptions.ordered_properties;
423	    table_printer.value_formatter.single_line = formatOptions.single_line;
424	
425	    switch (formatOptions.enable_colors) {
426	        inline else => |colors| table_printer.printTable(Writer, writer, colors) catch {
427	            if (!globalThis.hasException())
428	                return globalThis.throwOutOfMemory();
429	            return .zero;
430	        },
431	    }
432	
433	    writer.flush() catch |e| switch (e) {
434	        error.WriteFailed => return error.OutOfMemory,
435	    };
436	
437	    return bun.String.createUTF8ForJS(globalThis, array.written());
438	}
