440	pub fn inspect(globalThis: *jsc.JSGlobalObject, callframe: *jsc.CallFrame) bun.JSError!jsc.JSValue {
441	    const arguments = callframe.arguments_old(4).slice();
442	    if (arguments.len == 0)
443	        return bun.String.empty.toJS(globalThis);
444	
445	    for (arguments) |arg| {
446	        arg.protect();
447	    }
448	    defer {
449	        for (arguments) |arg| {
450	            arg.unprotect();
451	        }
452	    }
453	
454	    var formatOptions = ConsoleObject.FormatOptions{
455	        .enable_colors = false,
456	        .add_newline = false,
457	        .flush = false,
458	        .max_depth = 8,
459	        .quote_strings = true,
460	        .ordered_properties = false,
461	    };
462	    if (arguments.len > 1) {
463	        try formatOptions.fromJS(globalThis, arguments[1..]);
464	    }
465	
466	    // very stable memory address
467	    var array = std.Io.Writer.Allocating.init(bun.default_allocator);
468	    defer array.deinit();
469	    const writer = &array.writer;
470	    // we buffer this because it'll almost always be < 4096
471	    // when it's under 4096, we want to avoid the dynamic allocation
472	    try ConsoleObject.format2(
473	        .Debug,
474	        globalThis,
475	        arguments.ptr,
476	        1,
477	        writer,
478	        formatOptions,
479	    );
480	    if (globalThis.hasException()) return error.JSError;
481	    writer.flush() catch return globalThis.throwOutOfMemory();
482	
483	    // we are going to always clone to keep things simple for now
484	    // the common case here will be stack-allocated, so it should be fine
485	    var out = ZigString.init(array.written()).withEncoding();
486	    const ret = out.toJS(globalThis);
487	
488	    return ret;
489	}
