571	fn getMain(globalThis: *jsc.JSGlobalObject) callconv(jsc.conv) jsc.JSValue {
572	    const vm = globalThis.bunVM();
573	    // If JS has set it to a custom value, use that one
574	    if (vm.overridden_main.get()) |overridden_main| return overridden_main;
575	
576	    // Attempt to use the resolved filesystem path
577	    // This makes `eval('require.main === module')` work when the main module is a symlink.
578	    // This behavior differs slightly from Node. Node sets the `id` to `.` when the main module is a symlink.
579	    use_resolved_path: {
580	        if (vm.main_resolved_path.isEmpty()) {
581	            // If it's from eval, don't try to resolve it.
582	            if (strings.hasSuffixComptime(vm.main, "[eval]")) {
583	                break :use_resolved_path;
584	            }
585	            if (strings.hasSuffixComptime(vm.main, "[stdin]")) {
586	                break :use_resolved_path;
587	            }
588	
589	            const fd = bun.sys.openatA(
590	                if (comptime Environment.isWindows) bun.invalid_fd else bun.FD.cwd(),
591	                vm.main,
592	
593	                // Open with the minimum permissions necessary for resolving the file path.
594	                if (comptime Environment.isLinux) bun.O.PATH else bun.O.RDONLY,
595	
596	                0,
597	            ).unwrap() catch break :use_resolved_path;
598	
599	            defer fd.close();
600	            if (comptime Environment.isWindows) {
601	                var wpath: bun.WPathBuffer = undefined;
602	                const fdpath = bun.getFdPathW(fd, &wpath) catch break :use_resolved_path;
603	                vm.main_resolved_path = bun.String.cloneUTF16(fdpath);
604	            } else {
605	                var path: bun.PathBuffer = undefined;
606	                const fdpath = bun.getFdPath(fd, &path) catch break :use_resolved_path;
607	
608	                // Bun.main === otherId will be compared many times, so let's try to create an atom string if we can.
609	                if (bun.String.tryCreateAtom(fdpath)) |atom| {
610	                    vm.main_resolved_path = atom;
611	                } else {
612	                    vm.main_resolved_path = bun.String.cloneUTF8(fdpath);
613	                }
614	            }
615	        }
616	
617	        return vm.main_resolved_path.toJS(globalThis) catch .zero;
618	    }
619	
620	    return ZigString.init(vm.main).toJS(globalThis);
621	}
