639	    var line: ?string = null;
640	    var column: ?string = null;
641	
642	    if (arguments.nextEat()) |file_path_| {
643	        path = (try file_path_.toSlice(globalThis, arguments.arena.allocator())).slice();
644	    }
645	
646	    if (arguments.nextEat()) |opts| {
647	        if (!opts.isUndefinedOrNull()) {
648	            if (try opts.getTruthy(globalThis, "editor")) |editor_val| {
649	                var sliced = try editor_val.toSlice(globalThis, arguments.arena.allocator());
650	                const prev_name = edit.name;
651	
652	                if (!strings.eqlLong(prev_name, sliced.slice(), true)) {
653	                    const prev = edit.*;
654	                    edit.name = sliced.slice();
655	                    edit.detectEditor(VirtualMachine.get().transpiler.env);
656	                    editor_choice = edit.editor;
657	                    if (editor_choice == null) {
658	                        edit.* = prev;
659	                        return globalThis.throw("Could not find editor \"{s}\"", .{sliced.slice()});
660	                    } else if (edit.name.ptr == edit.path.ptr) {
661	                        edit.name = arguments.arena.allocator().dupe(u8, edit.path) catch unreachable;
662	                        edit.path = edit.path;
