664	                }
665	            }
666	
667	            if (try opts.getTruthy(globalThis, "line")) |line_| {
668	                line = (try line_.toSlice(globalThis, arguments.arena.allocator())).slice();
669	            }
670	
671	            if (try opts.getTruthy(globalThis, "column")) |column_| {
672	                column = (try column_.toSlice(globalThis, arguments.arena.allocator())).slice();
673	            }
