781	fn doResolve(globalThis: *jsc.JSGlobalObject, arguments: []const JSValue) bun.JSError!jsc.JSValue {
782	    var args = jsc.CallFrame.ArgumentsSlice.init(globalThis.bunVM(), arguments);
783	    defer args.deinit();
784	    const specifier = args.protectEatNext() orelse {
785	        return globalThis.throwInvalidArguments("Expected a specifier and a from path", .{});
786	    };
787	
788	    if (specifier.isUndefinedOrNull()) {
789	        return globalThis.throwInvalidArguments("specifier must be a string", .{});
790	    }
791	
792	    const from = args.protectEatNext() orelse {
793	        return globalThis.throwInvalidArguments("Expected a from path", .{});
794	    };
795	
796	    if (from.isUndefinedOrNull()) {
797	        return globalThis.throwInvalidArguments("from must be a string", .{});
798	    }
799	
800	    var is_esm = true;
801	    if (args.nextEat()) |next| {
802	        if (next.isBoolean()) {
803	            is_esm = next.toBoolean();
804	        } else {
805	            return globalThis.throwInvalidArguments("esm must be a boolean", .{});
806	        }
807	    }
808	
809	    const specifier_str = try specifier.toBunString(globalThis);
810	    defer specifier_str.deref();
811	    const from_str = try from.toBunString(globalThis);
812	    defer from_str.deref();
813	    return doResolveWithArgs(
814	        globalThis,
815	        specifier_str,
816	        from_str,
817	        is_esm,
818	        false,
819	        false,
820	    );
821	}
