823	fn doResolveWithArgs(ctx: *jsc.JSGlobalObject, specifier: bun.String, from: bun.String, is_esm: bool, comptime is_file_path: bool, is_user_require_resolve: bool) bun.JSError!jsc.JSValue {
824	    var errorable: ErrorableString = undefined;
825	    var query_string = ZigString.Empty;
826	
827	    const specifier_decoded = if (specifier.hasPrefixComptime("file://"))
828	        bun.jsc.URL.pathFromFileURL(specifier)
829	    else
830	        specifier.dupeRef();
831	    defer specifier_decoded.deref();
832	
833	    try VirtualMachine.resolveMaybeNeedsTrailingSlash(
834	        &errorable,
835	        ctx,
836	        specifier_decoded,
837	        from,
838	        &query_string,
839	        is_esm,
840	        is_file_path,
841	        is_user_require_resolve,
842	    );
843	
844	    if (!errorable.success) {
845	        return ctx.throwValue(errorable.result.err.value);
846	    }
847	
848	    if (query_string.len > 0) {
849	        var stack = std.heap.stackFallback(1024, ctx.allocator());
850	        const allocator = stack.get();
851	        var arraylist = std.array_list.Managed(u8).initCapacity(allocator, 1024) catch unreachable;
852	        defer arraylist.deinit();
853	        try arraylist.writer().print("{f}{f}", .{
854	            errorable.result.value,
855	            query_string,
856	        });
857	
858	        return ZigString.initUTF8(arraylist.items).toJS(ctx);
859	    }
860	
861	    return errorable.result.value.toJS(ctx);
862	}
