949	pub fn indexOfLine(globalThis: *jsc.JSGlobalObject, callframe: *jsc.CallFrame) bun.JSError!jsc.JSValue {
950	    const arguments_ = callframe.arguments_old(2);
951	    const arguments = arguments_.slice();
952	    if (arguments.len == 0) {
953	        return jsc.JSValue.jsNumberFromInt32(-1);
954	    }
955	
956	    var buffer = arguments[0].asArrayBuffer(globalThis) orelse {
957	        return jsc.JSValue.jsNumberFromInt32(-1);
958	    };
959	
960	    var offset: usize = 0;
961	    if (arguments.len > 1) {
962	        const offset_value = try arguments[1].coerce(i64, globalThis);
963	        offset = @intCast(@max(offset_value, 0));
964	    }
965	
966	    const bytes = buffer.byteSlice();
967	    var current_offset = offset;
968	    const end = @as(u32, @truncate(bytes.len));
969	
970	    while (current_offset < end) {
971	        if (strings.indexOfNewlineOrNonASCII(bytes, @as(u32, @truncate(current_offset)))) |i| {
972	            const byte = bytes[i];
973	            if (byte > 0x7F) {
974	                current_offset += @max(strings.wtf8ByteSequenceLength(byte), 1);
975	                continue;
976	            }
977	
978	            if (byte == '\n') {
979	                return jsc.JSValue.jsNumber(i);
980	            }
981	
982	            current_offset = i + 1;
983	        } else {
984	            break;
985	        }
986	    }
987	
988	    return jsc.JSValue.jsNumberFromInt32(-1);
989	}
