pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const arguments = callframe.arguments_old(1).slice();
    if (arguments.len == 0 or arguments[0].isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    const value = arguments[0];
    if (!value.isObject()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    try stringifyObject(globalThis, value, &builder, null);

    return builder.toString(globalThis);
}

fn stringifyObject(
    globalThis: *jsc.JSGlobalObject,
    value: jsc.JSValue,
    builder: *wtf.StringBuilder,
    section: ?bun.String,
) bun.JSError!void {
    const obj = try value.toObject(globalThis);

    // Collect nested objects to emit after scalar keys
    var nested_keys: std.ArrayListUnmanaged(bun.String) = .empty;
    var nested_values: std.ArrayListUnmanaged(jsc.JSValue) = .empty;
    defer nested_keys.deinit(bun.default_allocator);
    defer nested_values.deinit(bun.default_allocator);

    var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
        globalThis,
        obj,
    );
    defer iter.deinit();

    // Emit section header if present
    if (section) |sec| {
        builder.append(.lchar, '[');
        builder.append(.string, sec);
        builder.append(.lchar, ']');
        builder.append(.lchar, '\n');
    }

    // First pass: emit scalar values, collect nested objects
    while (try iter.next()) |prop_name| {
        const prop_value = iter.value;

        if (prop_value.isObject() and !prop_value.isArray() and !prop_value.isFunction()) {
            nested_keys.append(bun.default_allocator, prop_name) catch return error.OutOfMemory;
            nested_values.append(bun.default_allocator, prop_value) catch return error.OutOfMemory;
            continue;
        }

        builder.append(.string, prop_name);
        builder.append(.latin1, " = ");
        try appendValue(globalThis, prop_value, builder);
        builder.append(.lchar, '\n');
    }

    // Second pass: emit nested objects as sections
    for (nested_keys.items, nested_values.items) |key, val| {
        builder.append(.lchar, '\n');
        try stringifyObject(globalThis, val, builder, key);
    }
}

fn appendValue(
    globalThis: *jsc.JSGlobalObject,
    value: jsc.JSValue,
    builder: *wtf.StringBuilder,
) bun.JSError!void {
    if (value.isBoolean()) {
        builder.append(.latin1, if (value.asBoolean()) "true" else "false");
        return;
    }

    if (value.isNull()) {
        builder.append(.latin1, "null");
        return;
    }

    if (value.isNumber()) {
        if (value.isInt32()) {
            builder.append(.int, value.asInt32());
        } else {
            builder.append(.double, value.asNumber());
        }
        return;
    }

    if (value.isString()) {
        const str = try value.toBunString(globalThis);
        defer str.deref();
        builder.append(.string, str);
        return;
    }

    if (value.isArray()) {
        // Arrays are not natively supported in INI but we emit comma-separated values
        var arr_iter = try value.arrayIterator(globalThis);
        var first = true;
        while (try arr_iter.next()) |item| {
            if (!first) builder.append(.latin1, ", ");
            first = false;
            try appendValue(globalThis, item, builder);
        }
        return;
    }

    // Fallback: convert to string
    const str = try value.toBunString(globalThis);
    defer str.deref();
    builder.append(.string, str);
}

fn parseINI(globalThis: *jsc.JSGlobalObject, input: []const u8) bun.JSError!jsc.JSValue {
    const root = JSValue.createEmptyObject(globalThis, 0);
    var current_section = root;
    var line_num: usize = 0;

    var remaining = input;
    while (remaining.len > 0) {
        line_num += 1;
        const line_end = std.mem.indexOfScalar(u8, remaining, '\n') orelse remaining.len;
        const raw_line = remaining[0..line_end];
        remaining = if (line_end < remaining.len) remaining[line_end + 1 ..] else &.{};

        // Strip \r for CRLF
        const line_trimmed = std.mem.trimRight(u8, raw_line, "\r");
        // Trim whitespace
        const line = std.mem.trim(u8, line_trimmed, " \t");

        // Skip empty lines
        if (line.len == 0) continue;

        // Skip comment lines
        if (line[0] == ';' or line[0] == '#') continue;

        // Section header
        if (line[0] == '[') {
            const close = std.mem.indexOfScalar(u8, line, ']') orelse {
                return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                    "INI Parse error: unclosed section header on line {d}",
                    .{line_num},
                ));
            };
            const section_name = std.mem.trim(u8, line[1..close], " \t");
            if (section_name.len == 0) {
                return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                    "INI Parse error: empty section name on line {d}",
                    .{line_num},
                ));
            }

            // Get or create the section object
            var name_str = bun.String.borrowUTF8(section_name);
            defer name_str.deref();
            const existing = root.getWithString(globalThis, &name_str);
            if (existing != .js_undefined and existing != .zero) {
                current_section = existing;
            } else {
                const section_obj = JSValue.createEmptyObject(globalThis, 0);
                try root.putMayBeIndex(globalThis, &name_str, section_obj);
                current_section = section_obj;
            }
            continue;
        }

        // Key=value pair
        const eq_pos = std.mem.indexOfScalar(u8, line, '=') orelse {
            return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                "INI Parse error: expected '=' on line {d}",
                .{line_num},
            ));
        };

        const key = std.mem.trimRight(u8, line[0..eq_pos], " \t");
        if (key.len == 0) {
            return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                "INI Parse error: empty key on line {d}",
                .{line_num},
            ));
        }

        var raw_value = std.mem.trimLeft(u8, line[eq_pos + 1 ..], " \t");

        // Strip inline comments (only if preceded by whitespace)
        raw_value = stripInlineComment(raw_value);

        // Strip surrounding quotes
        const value_str = stripQuotes(raw_value);

        // Convert to appropriate JS value
        var key_str = bun.String.borrowUTF8(key);
        defer key_str.deref();
        const js_value = parseValue(globalThis, value_str);
        try current_section.putMayBeIndex(globalThis, &key_str, js_value);
    }

    return root;
}

fn stripInlineComment(value: []const u8) []const u8 {
    // Look for ; or # preceded by whitespace
    var i: usize = 0;
    var in_single_quote = false;
    var in_double_quote = false;
    while (i < value.len) : (i += 1) {
        const c = value[i];
        if (c == '\'' and !in_double_quote) {
            in_single_quote = !in_single_quote;
        } else if (c == '"' and !in_single_quote) {
            in_double_quote = !in_double_quote;
        } else if (!in_single_quote and !in_double_quote and (c == ';' or c == '#')) {
            // Only strip if preceded by whitespace
            if (i > 0 and (value[i - 1] == ' ' or value[i - 1] == '\t')) {
                return std.mem.trimRight(u8, value[0 .. i - 1], " \t");
            }
        }
    }
    return value;
}

fn stripQuotes(value: []const u8) []const u8 {
    if (value.len >= 2) {
        if ((value[0] == '"' and value[value.len - 1] == '"') or
            (value[0] == '\'' and value[value.len - 1] == '\''))
        {
            return value[1 .. value.len - 1];
        }
    }
    return value;
}

fn parseValue(globalThis: *jsc.JSGlobalObject, value: []const u8) jsc.JSValue {
    // Empty value
    if (value.len == 0) return bun.String.borrowUTF8("").toJS(globalThis);

    // Boolean values
    if (std.ascii.eqlIgnoreCase(value, "true")) return JSValue.jsBoolean(true);
    if (std.ascii.eqlIgnoreCase(value, "false")) return JSValue.jsBoolean(false);

    // Null
    if (std.ascii.eqlIgnoreCase(value, "null")) return .null;

    // Try integer
    if (std.fmt.parseInt(i64, value, 10)) |int_val| {
        if (int_val >= std.math.minInt(i32) and int_val <= std.math.maxInt(i32)) {
            return JSValue.jsNumber(@as(i32, @intCast(int_val)));
        }
        return JSValue.jsNumber(@as(f64, @floatFromInt(int_val)));
    } else |_| {}

    // Try float
    if (std.fmt.parseFloat(f64, value)) |float_val| {
        return JSValue.jsNumber(float_val);
    } else |_| {}

    // String value
    var str = bun.String.borrowUTF8(value);
    defer str.deref();
    return str.toJS(globalThis);
}

